  ('judicial-57f41407-moex-00129', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲並無犯罪前科，某日突於酒後在街上大吵大鬧，員警獲報到場勸阻，甲動手打員警一巴掌（未成傷） 後離去，甲酒醒後深感後悔，自行前往警局投案，員警製作筆錄後移送檢察官複訊，檢察官以甲犯妨 害公務罪，罪嫌重大且有逃亡事實，當庭逮捕甲後向法院聲請羈押，下列何者正確？', '["甲並非現行犯，故檢察官不能逮捕甲", "甲不可以聲請提審", "甲請求法院交保，法院不得駁回", "法院開羈押庭訊問被告，均不得於夜間行之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
